// StopScopeTenant restricts a query to a single tenant by adding:
//
//	WHERE stp.organization_id = ? AND stp.business_unit_id = ?
//
// Returns the same *bun.SelectQuery so it can be chained fluently:
//
//	buncolgen.StopScopeTenant(sq, ti).
//		Where(buncolgen.StopColumns.ID.Eq(), id)
func StopScopeTenant(q *bun.SelectQuery, ti pagination.TenantInfo) *bun.SelectQuery {
	return ScopeTenant(q, StopColumns.OrganizationID, StopColumns.BusinessUnitID, ti)
}

// StopScopeTenantUpdate restricts an update query to a single tenant.
// Use this inside UpdateQuery.WhereGroup callbacks:
//
//	WhereGroup(" AND ", func(uq *bun.UpdateQuery) *bun.UpdateQuery {
//		return buncolgen.StopScopeTenantUpdate(uq, req.TenantInfo).
//			Where(buncolgen.StopColumns.ID.In(), bun.List(ids))
//	})
func StopScopeTenantUpdate(q *bun.UpdateQuery, ti pagination.TenantInfo) *bun.UpdateQuery {
	return ScopeTenantUpdate(q, StopColumns.OrganizationID, StopColumns.BusinessUnitID, ti)
}

// StopScopeTenantDelete restricts a delete query to a single tenant.
// Use this inside DeleteQuery.WhereGroup callbacks:
//
//	WhereGroup(" AND ", func(dq *bun.DeleteQuery) *bun.DeleteQuery {
//		return buncolgen.StopScopeTenantDelete(dq, req.TenantInfo).
//			Where(buncolgen.StopColumns.ID.Eq(), id)
//	})
func StopScopeTenantDelete(q *bun.DeleteQuery, ti pagination.TenantInfo) *bun.DeleteQuery {
	return ScopeTenantDelete(q, StopColumns.OrganizationID, StopColumns.BusinessUnitID, ti)
}

// StopApplyTenant returns a closure for SelectQuery.Apply() that scopes to a single tenant.
// Use this instead of wrapping ScopeTenant in an anonymous function:
//
//	q.Apply(buncolgen.StopApplyTenant(tenantInfo))
func StopApplyTenant(ti pagination.TenantInfo) func(*bun.SelectQuery) *bun.SelectQuery {
	return ApplyTenant(StopColumns.OrganizationID, StopColumns.BusinessUnitID, ti)
}

